catalog_script_client.script:
   function onLoad() {
    // 1. Get the query string safely using search parameters
    var urlParams = new URLSearchParams(top.location.search);
    var vendorSysId = urlParams.get('vendor_sys_id');

    // Optional console log to track execution
    console.log('Detected vendor_sys_id from URL: ' + vendorSysId);

    // Stop execution early if no ID is found in the URL
    if (!vendorSysId) {
        return;
    }

    // 2. Instantiate 'ga' FIRST before adding parameters
    var ga = new GlideAjax('VendorRenewalAjax'); 

    // 3. Define parameters
    ga.addParam('sysparm_name', 'getVendorDetails');
    ga.addParam('sysparm_vendor_sys_id', vendorSysId);

    // 4. Fire the server request asynchronously
    ga.getXMLAnswer(function(response) {
        if (!response) {
            console.error('No response received from VendorRenewalAjax');
            return;
        }

        try {
            var data = JSON.parse(response);
			console.log('data: ', data);
            // Handle errors thrown back explicitly from script include
            if (data.error) {
                console.error('Server Script Include Error: ' + data.error);
                return;
            }

            // 5. Populate standard text fields and choice lists
            g_form.setValue('number', data.vendor_code);
            g_form.setValue('vendor_name', data.vendor_name);
            g_form.setValue('vendor_contact', data.vendor_contact); 
            g_form.setValue('state', data.state); 
            g_form.setValue('vendor_sys_id', vendorSysId);



            // 6. Populate the Reference field cleanly using ID and Display Value
            if (data.vendor_manager_id) {
				console.log('vendor_manager', data.vendor_manager);
                g_form.setValue('vendor_manager', data.vendor_manager_dv);
            } else {
                g_form.clearValue('vendor_manager');
            }

        } catch (error) {
            console.error('Parsing error inside GlideAjax response: ', error);
        }
    });
}
